69	postgres	INSERT	support_tickets	2	Record created	\N	{"id": 2, "status": "solved", "line_id": 5, "user_id": 1, "client_id": 5, "created_at": "2026-01-14T11:49:42.848139+04:00", "updated_at": "2026-01-14T11:49:42.848139+04:00", "reported_at": "2026-01-13T18:47:00+04:00", "resolved_at": null, "contact_name": "Светлана Худякова", "support_line": 1, "problem_description": "Сообщение из ТГ\\n\\"Жанна, добрый день! У меня возникла проблема с отправкой кодов на проверку в ЧЗ. Дело вот в чем. При фасовке были утеряны 2 кода и во избежания простоя я распечатала дополнительные. В связи с этим для отправки отчета о нанесении я использовала выгрузку кодов из WMS, но система пишет ошибку. Формат одного кода не соответствует. Я нашла в выгрузке из ЧЗ похожий и сравнила. коды одинаковые за исключением ковычек. В первом случае код с ' а в кодах из ЧЗ \\". Почему могло такое произойти и что с этим делать?\\"", "solution_description": "Проблема была со стороны Логикон (WMS)."}	2026-01-14 11:49:42.848139+04	\N	\N
