2284	postgres	UPDATE	sites	6	Record updated	{"id": 6, "name": "Старая Купавна", "notes": "ТГ группа с Мотрум-Авиафлюид-Логикон: \\n\\"Взаимодействие Мотрум-Логикон\\"", "address": "Московская обл., Старая Купавна", "client_id": 5, "created_at": "2026-01-14T11:35:26.79735+04:00", "updated_at": "2026-01-30T08:57:57.446489+04:00", "l3_provider": "Контур", "l3_provider_custom": null}	{"id": 6, "name": "Старая Купавна", "notes": "\\n               [GUID] - уникальный идентификатор записи\\n\\n                               Уникальный номер записи БД.\\n\\n[SKU] - код товара формируемый в 1C (уникальный и не равен GTIN), [nvarchar](50), NOT NULL\\n\\n                               Уникальный код товара (артикул), должен вводиться на линии перед началом производства продукции\\n\\n               [ID] - номер паллеты, [nvarchar](50), NOT NULL\\n\\n                               SSCC код паллеты\\n\\n               [BOXID] - номер коробки, [nvarchar](50), NULL\\n\\n                               SSCC код коробки\\n\\n               [SERIALNUMBER] - номер марки честного знака, уникальное поле, [nvarchar](250), NOT NULL\\n\\n                               Короткий номер марки честного знака (без криптозащиты). Необходимо уточнить длину марки у Контура.\\n\\n               [SERIALNUMBERLONG] - номер марки честного знака, уникальное поле, [nvarchar](250), NOT NULL\\n\\n                               Полный номер марки честного знака (с криптозащитой). Необходимо уточнить длину марки у Контура.\\n\\n               [LOTTABLE02] - производственная партия, [nvarchar](50), NOT NULL\\n\\nНеотъемлемый атрибут товара. Должен вводиться на линии перед началом производства продукции. Принцип формирования нужно уточнить у Авиафлюид.\\n\\n               [LOTTABLE04] - дата производства[date], NOT NULL\\n\\n                               Неотъемлемый атрибут товара. Необходимо уточнить у Авиафлюид принцип его формирования (одна дата для всей партии или текущая дата)\\n\\n               [STATUS] - статус обработки записи, [int], по умолчанию равен 0, NOT NULL\\n\\n                               Всегда заполняется значением 0. Далее меняется WMS.\\n\\n               [ADDWHO] - автор записи (номер линии) [nvarchar](18) NOT NULL\\n\\n                               Заполняется названием линии, которая выпустила палллет.\\n\\n               [ADDDATE] - дата добавления записи, [datetime], NOT NULL\\n\\n                               Текущая дата и время записи по Гринвичу.\\n\\n               [EDITWHO] - автор обновления записи, NULL\\n\\n                               Не заполняется. Далее меняется WMS.\\n\\n               [EDITDATE] - дата [datetime] NULL\\n\\n                               Не заполняется. Далее меняется WMS.", "address": "Московская обл., Старая Купавна", "client_id": 5, "created_at": "2026-01-14T11:35:26.79735+04:00", "updated_at": "2026-04-08T14:06:35.053911+04:00", "l3_provider": "Контур", "l3_provider_custom": null}	2026-04-08 14:06:35.053911+04	\N	\N
