2359	postgres	UPDATE	knowledge_base	1	Record updated	{"id": 1, "tags": ["печать", "код", "datamatrix", "размер"], "title": "Как правильно рассчитать размер DataMatrix для печати", "content": "<h2 id=\\"id-russia\\"><a target=\\"_blank\\" rel=\\"noopener noreferrer nofollow\\" href=\\"https://id-russia.ru/company/stati/414-kak-rasschitat-razmer-datamatrix/\\">Статья ID-Russia</a></h2><h3 id=\\"datamatrix\\">Как правильно рассчитать размер DataMatrix для печати</h3><p>В статье описано, как рассчитывается размер кода и есть удобный селектор по разным товарным группам, с разным разрешением печати dpi </p><p>![Фото](https://id-russia.ru/images/IDRussia/marking_photo/stroka_sravnenie_new2.png) ![Фото](https://id-russia.ru/images/IDRussia/marking_photo/legenda_shema_new.png)</p>", "category": "Печать", "parent_id": null, "created_at": "2026-01-13T16:14:29.314807+04:00", "updated_at": "2026-04-06T13:57:17.712684+04:00", "display_order": null}	{"id": 1, "tags": ["печать", "код", "datamatrix", "размер"], "title": "Как правильно рассчитать размер DataMatrix для печати", "content": "<h2 id=\\"id-russia\\"><a target=\\"_blank\\" rel=\\"noopener noreferrer nofollow\\" href=\\"https://id-russia.ru/company/stati/414-kak-rasschitat-razmer-datamatrix/\\">Статья ID-Russia</a></h2><h3 id=\\"datamatrix\\">Как правильно рассчитать размер DataMatrix для печати</h3><p>В статье описано, как рассчитывается размер кода и есть удобный селектор по разным товарным группам, с разным разрешением печати dpi </p><p>![Фото](https://id-russia.ru/images/IDRussia/marking_photo/stroka_sravnenie_new2.png) ![Фото](https://id-russia.ru/images/IDRussia/marking_photo/legenda_shema_new.png)</p>", "category": "Печать", "parent_id": null, "created_at": "2026-01-13T16:14:29.314807+04:00", "updated_at": "2026-04-15T16:21:17.248413+04:00", "display_order": null}	2026-04-15 16:21:17.248413+04	\N	\N
