--
-- Name: equipment_details; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.equipment_details AS
 SELECT e.id,
    e.serial_number,
    e.model,
    e.status,
    e.install_date,
    e.notes,
    e.ip_address,
    e.subnet_mask,
    e.gateway,
    et.name AS equipment_type,
    et.description AS equipment_type_description,
    pl.name AS production_line,
    pl.description AS line_description,
    s.name AS site,
    s.address AS site_address,
    c.name AS client,
    c.contact_info AS client_contact,
    e.created_at,
    e.updated_at
   FROM ((((public.equipment e
     JOIN public.equipment_types et ON ((e.type_id = et.id)))
     JOIN public.production_lines pl ON ((e.line_id = pl.id)))
     JOIN public.sites s ON ((pl.site_id = s.id)))
     JOIN public.clients c ON ((s.client_id = c.id)));


ALTER VIEW public.equipment_details OWNER TO postgres;

