--
-- Name: line_summary; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.line_summary AS
 SELECT pl.id,
    pl.name,
    pl.description,
    pl.db_ip,
    pl.db_name,
    s.name AS site_name,
    s.address AS site_address,
    c.name AS client_name,
    count(e.id) AS equipment_count,
    count(
        CASE
            WHEN (e.status = 'active'::public.equipment_status_enum) THEN 1
            ELSE NULL::integer
        END) AS active_equipment,
    count(
        CASE
            WHEN (e.status = 'maintenance'::public.equipment_status_enum) THEN 1
            ELSE NULL::integer
        END) AS maintenance_equipment,
    count(
        CASE
            WHEN (e.status = 'faulty'::public.equipment_status_enum) THEN 1
            ELSE NULL::integer
        END) AS faulty_equipment,
    count(ra.id) AS remote_access_count
   FROM ((((public.production_lines pl
     JOIN public.sites s ON ((pl.site_id = s.id)))
     JOIN public.clients c ON ((s.client_id = c.id)))
     LEFT JOIN public.equipment e ON ((pl.id = e.line_id)))
     LEFT JOIN public.remote_access ra ON ((pl.id = ra.line_id)))
  GROUP BY pl.id, pl.name, pl.description, pl.db_ip, pl.db_name, s.name, s.address, c.name;


ALTER VIEW public.line_summary OWNER TO postgres;

